import{_ as e,c as o,o as a,a1 as s}from"./chunks/framework.DILC4Csi.js";const h=JSON.parse('{"title":"项目初始化: 快速建立记忆 | opencode-supermemory","description":"学习如何使用 /supermemory-init 命令让 Agent 深度扫描代码库，自动提取架构和规范并存入持久记忆，实现跨会话的上下文保持。","frontmatter":{"title":"项目初始化: 快速建立记忆 | opencode-supermemory","sidebarTitle":"让 Agent 记住项目","subtitle":"项目初始化: 快速建立记忆","description":"学习如何使用 /supermemory-init 命令让 Agent 深度扫描代码库，自动提取架构和规范并存入持久记忆，实现跨会话的上下文保持。","tags":["初始化","记忆生成","工作流"],"prerequisite":["start-getting-started"],"order":2},"headers":[],"relativePath":"zh/supermemoryai/opencode-supermemory/start/initialization/index.md","filePath":"zh/supermemoryai/opencode-supermemory/start/initialization/index.md"}'),i={name:"zh/supermemoryai/opencode-supermemory/start/initialization/index.md"};function r(n,t,l,d,c,p){return a(),o("div",null,[...t[0]||(t[0]=[s(`<h1 id="项目初始化-建立第一印象" tabindex="-1">项目初始化：建立第一印象 <a class="header-anchor" href="#项目初始化-建立第一印象" aria-label="Permalink to &quot;项目初始化：建立第一印象&quot;">​</a></h1><h2 id="学完你能做什么" tabindex="-1">学完你能做什么 <a class="header-anchor" href="#学完你能做什么" aria-label="Permalink to &quot;学完你能做什么&quot;">​</a></h2><ul><li><strong>一键熟悉项目</strong>：让 Agent 像新入职员工一样，主动探索并理解整个代码库。</li><li><strong>建立长期记忆</strong>：自动提取项目的技术栈、架构模式和编码规范，存入 Supermemory。</li><li><strong>消除重复解释</strong>：再也不用在每次会话开始时重复 &quot;我们用的是 Bun&quot; 或 &quot;所有组件都要写测试&quot;。</li></ul><h2 id="你现在的困境" tabindex="-1">你现在的困境 <a class="header-anchor" href="#你现在的困境" aria-label="Permalink to &quot;你现在的困境&quot;">​</a></h2><p>你是否遇到过这些情况：</p><ul><li><strong>重复劳动</strong>：每次开启新会话，都要花大量篇幅告诉 Agent 项目的基本情况。</li><li><strong>上下文遗忘</strong>：Agent 经常忘记项目特定的目录结构，把文件建错位置。</li><li><strong>规范不统一</strong>：Agent 写的代码风格飘忽不定，一会儿用 <code>interface</code> 一会儿用 <code>type</code>。</li></ul><h2 id="什么时候用这一招" tabindex="-1">什么时候用这一招 <a class="header-anchor" href="#什么时候用这一招" aria-label="Permalink to &quot;什么时候用这一招&quot;">​</a></h2><ul><li><strong>刚安装插件后</strong>：这是使用 opencode-supermemory 的第一步。</li><li><strong>接手新项目时</strong>：快速建立该项目的记忆库。</li><li><strong>重大重构后</strong>：当项目架构发生变化，需要更新 Agent 的认知时。</li></ul><h2 id="🎒-开始前的准备" tabindex="-1">🎒 开始前的准备 <a class="header-anchor" href="#🎒-开始前的准备" aria-label="Permalink to &quot;🎒 开始前的准备&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">前置检查</p><p>请确保你已经完成了 <a href="./../getting-started/">快速开始</a> 中的安装和配置步骤，并且 <code>SUPERMEMORY_API_KEY</code> 已正确设置。</p></div><h2 id="核心思路" tabindex="-1">核心思路 <a class="header-anchor" href="#核心思路" aria-label="Permalink to &quot;核心思路&quot;">​</a></h2><p><code>/supermemory-init</code> 命令本质上不是一个二进制程序，而是一个<strong>精心设计的 Prompt</strong>（提示词）。</p><p>当你运行这个命令时，它会向 Agent 发送一份详细的&quot;入职指南&quot;，指示 Agent：</p><ol><li><strong>深度调研</strong>：主动阅读 <code>README.md</code>、<code>package.json</code>、Git 提交记录等。</li><li><strong>结构化分析</strong>：识别项目的技术栈、架构模式、隐式约定。</li><li><strong>持久化存储</strong>：使用 <code>supermemory</code> 工具将这些洞察存入云端数据库。</li></ol><div class="info custom-block"><p class="custom-block-title">记忆作用域</p><p>初始化过程会区分两种记忆：</p><ul><li><strong>Project Scope</strong>：仅对当前项目生效（如：构建命令、目录结构）。</li><li><strong>User Scope</strong>：对你所有项目生效（如：你偏好的代码风格）。</li></ul></div><h2 id="跟我做" tabindex="-1">跟我做 <a class="header-anchor" href="#跟我做" aria-label="Permalink to &quot;跟我做&quot;">​</a></h2><h3 id="第-1-步-运行初始化命令" tabindex="-1">第 1 步：运行初始化命令 <a class="header-anchor" href="#第-1-步-运行初始化命令" aria-label="Permalink to &quot;第 1 步：运行初始化命令&quot;">​</a></h3><p>在 OpenCode 的输入框中，输入以下命令并发送：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/supermemory-init</span></span></code></pre></div><p><strong>为什么</strong> 这会加载预定义的 Prompt，启动 Agent 的探索模式。</p><p><strong>你应该看到</strong> Agent 开始回复，表示它理解了任务，并开始规划调研步骤。它可能会说：&quot;I will start by exploring the codebase structure and configuration files...&quot;</p><h3 id="第-2-步-观察-agent-的探索过程" tabindex="-1">第 2 步：观察 Agent 的探索过程 <a class="header-anchor" href="#第-2-步-观察-agent-的探索过程" aria-label="Permalink to &quot;第 2 步：观察 Agent 的探索过程&quot;">​</a></h3><p>Agent 会自动执行一系列操作，你只需要看着就行。它通常会：</p><ol><li><strong>读取配置文件</strong>：读取 <code>package.json</code>、<code>tsconfig.json</code> 等了解技术栈。</li><li><strong>查看 Git 历史</strong>：运行 <code>git log</code> 了解提交规范和活跃贡献者。</li><li><strong>探索目录结构</strong>：使用 <code>ls</code> 或 <code>list_files</code> 查看项目布局。</li></ol><p><strong>示例输出</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[Agent] Reading package.json to identify dependencies...</span></span>
<span class="line"><span>[Agent] Running git log to understand commit conventions...</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">消耗提示</p><p>这个过程是一次深度调研，可能会消耗较多的 Token（通常会进行 50+ 次工具调用）。请耐心等待，直到 Agent 报告完成。</p></div><h3 id="第-3-步-验证生成的记忆" tabindex="-1">第 3 步：验证生成的记忆 <a class="header-anchor" href="#第-3-步-验证生成的记忆" aria-label="Permalink to &quot;第 3 步：验证生成的记忆&quot;">​</a></h3><p>当 Agent 提示初始化完成后，你可以检查一下它到底记住了什么。输入：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/ask</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 列出当前项目的记忆</span></span></code></pre></div><p>或者直接调用工具（如果你想看原始数据）：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>supermemory(mode: &quot;list&quot;, scope: &quot;project&quot;)</span></span></code></pre></div><p><strong>你应该看到</strong> Agent 列出了一系列结构化的记忆，例如：</p><table tabindex="0"><thead><tr><th>类型</th><th>内容示例</th></tr></thead><tbody><tr><td><code>project-config</code></td><td>&quot;Uses Bun runtime. Build command: bun run build&quot;</td></tr><tr><td><code>architecture</code></td><td>&quot;API routes are located in src/routes/, using Hono framework&quot;</td></tr><tr><td><code>preference</code></td><td>&quot;Strict TypeScript usage: no &#39;any&#39; type allowed&quot;</td></tr></tbody></table><h3 id="第-4-步-补充遗漏-可选" tabindex="-1">第 4 步：补充遗漏（可选） <a class="header-anchor" href="#第-4-步-补充遗漏-可选" aria-label="Permalink to &quot;第 4 步：补充遗漏（可选）&quot;">​</a></h3><p>如果 Agent 漏掉了某些关键信息（比如某个只有口头约定的特殊规则），你可以手动补充：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>请记住：在这个项目中，所有的日期处理必须使用 dayjs 库，禁止使用原生 Date。</span></span></code></pre></div><p><strong>你应该看到</strong> Agent 回复确认，并调用 <code>supermemory(mode: &quot;add&quot;)</code> 保存这条新规则。</p><h2 id="检查点-✅" tabindex="-1">检查点 ✅ <a class="header-anchor" href="#检查点-✅" aria-label="Permalink to &quot;检查点 ✅&quot;">​</a></h2><ul><li>[ ] 运行 <code>/supermemory-init</code> 后，Agent 是否自动执行了探索任务？</li><li>[ ] 使用 <code>list</code> 命令是否能查看到新生成的记忆？</li><li>[ ] 记忆内容是否准确反映了当前项目的实际情况？</li></ul><h2 id="踩坑提醒" tabindex="-1">踩坑提醒 <a class="header-anchor" href="#踩坑提醒" aria-label="Permalink to &quot;踩坑提醒&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">不要频繁运行</p><p>初始化是一个耗时且消耗 Token 的过程。通常每个项目只需要运行一次。只有在项目发生巨大变化时才需要重新运行。</p></div><div class="danger custom-block"><p class="custom-block-title">隐私注意</p><p>虽然插件会自动脱敏 <code>&lt;private&gt;</code> 标签的内容，但在初始化过程中，Agent 会读取大量文件。请确保你的代码库中没有硬编码的敏感密钥（如 AWS Secret Key），否则它们可能会被作为&quot;项目配置&quot;存入记忆。</p></div><h2 id="本课小结" tabindex="-1">本课小结 <a class="header-anchor" href="#本课小结" aria-label="Permalink to &quot;本课小结&quot;">​</a></h2><p>通过 <code>/supermemory-init</code>，我们完成了从&quot;陌生人&quot;到&quot;熟练工&quot;的转变。现在，Agent 已经记住了项目的核心架构和规范，在接下来的编码任务中，它将自动利用这些上下文，为你提供更精准的辅助。</p><h2 id="下一课预告" tabindex="-1">下一课预告 <a class="header-anchor" href="#下一课预告" aria-label="Permalink to &quot;下一课预告&quot;">​</a></h2><blockquote><p>下一课我们学习 <strong><a href="./../../core/context-injection/">自动上下文注入机制</a></strong>。</p><p>你会学到：</p><ul><li>Agent 是如何在会话开始时&quot;想起&quot;这些记忆的。</li><li>如何通过关键词触发特定的记忆召回。</li></ul></blockquote><hr><h2 id="附录-源码参考" tabindex="-1">附录：源码参考 <a class="header-anchor" href="#附录-源码参考" aria-label="Permalink to &quot;附录：源码参考&quot;">​</a></h2><details><summary><strong>点击展开查看源码位置</strong></summary><blockquote><p>更新时间：2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>功能</th><th>文件路径</th><th>行号</th></tr></thead><tbody><tr><td>初始化 Prompt 定义</td><td><a href="https://github.com/supermemoryai/opencode-supermemory/blob/main/src/cli.ts#L13-L163" target="_blank" rel="noreferrer"><code>src/cli.ts</code></a></td><td>13-163</td></tr><tr><td>记忆工具实现</td><td><a href="https://github.com/supermemoryai/opencode-supermemory/blob/main/src/index.ts#L183-L485" target="_blank" rel="noreferrer"><code>src/index.ts</code></a></td><td>183-485</td></tr></tbody></table><p><strong>关键常量</strong>：</p><ul><li><code>SUPERMEMORY_INIT_COMMAND</code>：定义了 <code>/supermemory-init</code> 命令的具体 Prompt 内容，指导 Agent 如何进行调研和记忆。</li></ul></details>`,50)])])}const g=e(i,[["render",r]]);export{h as __pageData,g as default};
